const student = {
  name: "সাবরিনা",
  age: 22,
  isGraduated: false,
  greet() {
    console.log("আমি " + this.name);
  }
};

console.log(student.name);      // ডট নোটেশন
console.log(student["age"]);    // ব্র্যাকেট নোটেশন
student.greet();

// নতুন প্রপার্টি যুক্ত করা
student.department = "CSE";

const { name, age } = student; // ডিস্ট্রাকচারিং
console.log(name, age);

let text = "  Bangla Programming  ";
console.log(text.trim());                 // অতিরিক্ত স্পেস বাদ
console.log(text.toLowerCase());
console.log(text.toUpperCase());
console.log(text.includes("Bangla"));     // true
console.log(text.replace("Bangla", "বাংলা"));
console.log(text.trim().split(" "));      // অ্যারে তে ভাগ করা

let name = "রিমি";
console.log(`আমার নাম ${name}`);          // টেমপ্লেট লিটারাল
